class Solution {
    public int longestCommonSubsequence(String text1, String text2) {
        return dp(text1, text2, text1.length(), text2.length());
    }

    private int dp(String t1, String t2, int i, int j) {
        if (i == 0 || j == 0) return 0;
        if (t1.charAt(i - 1) == t2.charAt(j - 1)) {
            return 1 + dp(t1, t2, i - 1, j - 1);
        } else {
            return Math.max(dp(t1, t2, i - 1, j), dp(t1, t2, i, j - 1));
        }
    }
}

class Solution {
    public int longestCommonSubsequence(String text1, String text2) {
        int m = text1.length(), n = text2.length();
        int[][] memo = new int[m + 1][n + 1];
        for (int[] row : memo) Arrays.fill(row, -1);
        return dp(text1, text2, m, n, memo);
    }

    private int dp(String t1, String t2, int i, int j, int[][] memo) {
        if (i == 0 || j == 0) return 0;
        if (memo[i][j] != -1) return memo[i][j];
        if (t1.charAt(i - 1) == t2.charAt(j - 1)) {
            return memo[i][j] = 1 + dp(t1, t2, i - 1, j - 1, memo);
        } else {
            return memo[i][j] = Math.max(dp(t1, t2, i - 1, j, memo), dp(t1, t2, i, j - 1, memo));
        }
    }
}

class Solution {
    public int longestCommonSubsequence(String text1, String text2) {
        int m = text1.length(), n = text2.length();
        int[][] dp = new int[m + 1][n + 1];
        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (text1.charAt(i - 1) == text2.charAt(j - 1)) {
                    dp[i][j] = dp[i - 1][j - 1] + 1;
                } else {
                    dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]);
                }
            }
        }
        return dp[m][n];
    }
}
